#include "tree_traversals.h"
#include <stdlib.h>

static void inorder(int* arr, int n, int i, int* result, int* idx) {
    if (i >= n || arr[i] == -1) return;
    inorder(arr, n, 2 * i + 1, result, idx);
    result[(*idx)++] = arr[i];
    inorder(arr, n, 2 * i + 2, result, idx);
}

int* tree_traversals(int* arr, int n, int* out_size) {
    int* result = (int*)malloc(n * sizeof(int));
    int idx = 0;
    inorder(arr, n, 0, result, &idx);
    *out_size = idx;
    return result;
}

#include <vector>

static void inorder(const std::vector<int>& arr, int i, std::vector<int>& result) {
    if (i >= (int)arr.size() || arr[i] == -1) return;
    inorder(arr, 2 * i + 1, result);
    result.push_back(arr[i]);
    inorder(arr, 2 * i + 2, result);
}

std::vector<int> tree_traversals(std::vector<int> arr) {
    std::vector<int> result;
    inorder(arr, 0, result);
    return result;
}

using System.Collections.Generic;

public class TreeTraversals
{
    private static void Inorder(int[] arr, int i, List<int> result)
    {
        if (i >= arr.Length || arr[i] == -1) return;
        Inorder(arr, 2 * i + 1, result);
        result.Add(arr[i]);
        Inorder(arr, 2 * i + 2, result);
    }

    public static int[] Run(int[] arr)
    {
        List<int> result = new List<int>();
        Inorder(arr, 0, result);
        return result.ToArray();
    }
}

