func inorderHelper(arr []int, i int, result *[]int) {
	if i >= len(arr) || arr[i] == -1 {
		return
	}
	inorderHelper(arr, 2*i+1, result)
	*result = append(*result, arr[i])
	inorderHelper(arr, 2*i+2, result)
}

// TreeTraversals returns inorder traversal of a level-order binary tree array.
func TreeTraversals(arr []int) []int {
	result := []int{}
	inorderHelper(arr, 0, &result)
	return result
}

import java.util.*;

public class TreeTraversals {
    private static void inorder(int[] arr, int i, List<Integer> result) {
        if (i >= arr.length || arr[i] == -1) return;
        inorder(arr, 2 * i + 1, result);
        result.add(arr[i]);
        inorder(arr, 2 * i + 2, result);
    }

    public static int[] treeTraversals(int[] arr) {
        List<Integer> result = new ArrayList<>();
        inorder(arr, 0, result);
        return result.stream().mapToInt(Integer::intValue).toArray();
    }
}

private fun inorderHelper(arr: IntArray, i: Int, result: MutableList<Int>) {
    if (i >= arr.size || arr[i] == -1) return
    inorderHelper(arr, 2 * i + 1, result)
    result.add(arr[i])
    inorderHelper(arr, 2 * i + 2, result)
}

fun treeTraversals(arr: IntArray): IntArray {
    val result = mutableListOf<Int>()
    inorderHelper(arr, 0, result)
    return result.toIntArray()
}

def tree_traversals(arr: list[int]) -> list[int]:
    result = []
    def inorder(i):
        if i >= len(arr) or arr[i] == -1:
            return
        inorder(2 * i + 1)
        result.append(arr[i])
        inorder(2 * i + 2)
    inorder(0)
    return result

fn inorder_helper(arr: &[i32], i: usize, result: &mut Vec<i32>) {
    if i >= arr.len() || arr[i] == -1 { return; }
    inorder_helper(arr, 2 * i + 1, result);
    result.push(arr[i]);
    inorder_helper(arr, 2 * i + 2, result);
}

pub fn tree_traversals(arr: &[i32]) -> Vec<i32> {
    let mut result = Vec::new();
    inorder_helper(arr, 0, &mut result);
    result
}

object TreeTraversals {
  private def inorderHelper(arr: Array[Int], i: Int, result: scala.collection.mutable.ArrayBuffer[Int]): Unit = {
    if (i >= arr.length || arr(i) == -1) return
    inorderHelper(arr, 2 * i + 1, result)
    result += arr(i)
    inorderHelper(arr, 2 * i + 2, result)
  }

  def treeTraversals(arr: Array[Int]): Array[Int] = {
    val result = scala.collection.mutable.ArrayBuffer[Int]()
    inorderHelper(arr, 0, result)
    result.toArray
  }
}

private func inorderHelper(_ arr: [Int], _ i: Int, _ result: inout [Int]) {
    if i >= arr.count || arr[i] == -1 { return }
    inorderHelper(arr, 2 * i + 1, &result)
    result.append(arr[i])
    inorderHelper(arr, 2 * i + 2, &result)
}

func treeTraversals(_ arr: [Int]) -> [Int] {
    var result: [Int] = []
    inorderHelper(arr, 0, &result)
    return result
}

function inorderHelper(arr: number[], i: number, result: number[]): void {
    if (i >= arr.length || arr[i] === -1) return;
    inorderHelper(arr, 2 * i + 1, result);
    result.push(arr[i]);
    inorderHelper(arr, 2 * i + 2, result);
}

export function treeTraversals(arr: number[]): number[] {
    const result: number[] = [];
    inorderHelper(arr, 0, result);
    return result;
}
